#include &lt;vector&gt;
using namespace std;

bool backtrack(int idx, int k, int remainingSum, int remainingProduct, vector&lt;int&gt;&amp; nums) {
    if(idx == k) {
        return (remainingSum == 0 &amp;&amp; remainingProduct == 1);
    }
    for (int val = 1; val &lt;= remainingSum; val++) {
        if(remainingProduct % val != 0) continue;
        nums.push_back(val);
        if(backtrack(idx + 1, k, remainingSum - val, remainingProduct / val, nums))
            return true;
        nums.pop_back();
    }
    return false;
}

